import { FAN_ANIMATION, VERTICALALL_ANIMATION } from "../../../../core/animation-constants";
import { ParserRegistry } from "../../../../core/parser-registry";
import { isNumber, mergeJSON, perToPx } from "../../../../utils/zcutils";
import { bar_styles } from "../../../bar-encode";

const KEY = 'radialbar';
const E4 = 0.0001;

function position() {
    const { helpers } = this;
    const position = (helpers.position = {}),
        _position = (position[KEY] = {});

    helpers.utils = utils;

    helpers.positionComponent = {
        [KEY]: positionComponent()
    }

    _position.startAngle = startAngle.call(this);
    _position.endAngle = endAngle.call(this);
    _position.innerRadius = innerRadius.call(this);
    _position.outerRadius = outerRadius.call(this);
    _position.cornerRadius = cornerRadius.call(this);
    _position.padAngle = padAngle.call(this);
}

function positionComponent() {
    const defaultFunction = function (d, i, value) { return value };
    const component = {
        startAngle: defaultFunction,
        endAngle: defaultFunction,
        innerRadius: defaultFunction,
        outerRadius: defaultFunction,
        cornerRadius: defaultFunction,
        padAngle: defaultFunction
    }
    return component;
}

function styles() {
    bar_styles.call(this);

    const { helpers } = this;

    const _styles = helpers.styles[KEY];
    // let custom = {
    //     stroke: 'black'
    // }

    // mergeJSON(_styles, custom, true, true);
    return _styles[KEY];
}

function startAngle() {
    const self = this;
    const { chart, config, helpers, builderC, commonOption, rendererIndex: r_index } = this,
        { _getXYValue, animationOptions: anime, xscale, stacked } = builderC,
        xidx = chart.dataset.xidx,
        { positionComponent } = helpers,
        _positionComponent = positionComponent[KEY],
        barSeriesCount = stacked ? 1 : commonOption.barSeriesCount,
        s_index = stacked ? 0 : this.barDatasetIndex,   // used to calculate arc configs
        xcat_len = xscale.domain().length,
        bandwidth = xscale.bandwidth?.() ?? 0,
        radialOptions = config.merged('radial') || {},
        padding = radialOptions.padding ?? 0,
        interPadding = radialOptions.interPadding ?? 0;

    const findStartAngle = utils.findStartAngle(s_index, barSeriesCount, bandwidth);

    function enter(d, i) {
        let val;
        if (chart.phase == 'legendFilter') {
            return update.apply(this, arguments) + (i / xcat_len * bandwidth);
        };
        switch (anime.type) {
            case VERTICALALL_ANIMATION:
                val = update.apply(this, arguments);
            case FAN_ANIMATION:
                val = update.apply(this, arguments);
            default:
                val = update.apply(this, arguments);
        }
        return val;
    }
    function update(d, i) {
        // const padding = isNumber(interPadding) ? interPadding : perToPx(interPadding, bandwidth / 2, 0);
        let val =  findStartAngle(_getXYValue(d));
        // val = barSeriesCount > 1 ? findStartAngle(val, s_index) : val;
        return _positionComponent.startAngle.call(this, arguments[0], arguments[1], val);
    }
    function exit(d, i) {
        const {startAngle, endAngle } = this.zc_cache;
        const angle = startAngle + (i / (xcat_len + 1) * bandwidth); 
        // return this.zc_cache.startAngle;
        // const liveorder = d.liveorder || 0;
        return angle;
    }

    return { enter, update, exit };
}

function endAngle() {
    const self = this;
    const { chart, config, helpers, data, builderC, commonOption } = this,
        { _getXYValue, animationOptions: anime, xscale, yscale, stacked } = builderC,
        { position, positionComponent } = helpers,
        _position = position[KEY],
        _positionComponent = positionComponent[KEY],
        xcat_len = xscale.domain().length,
        xidx = chart.dataset.xidx,
        subseriesIdx = data.subseriesIdx || 0,
        barSeriesCount = stacked ? 1 : commonOption.barSeriesCount,
        s_index = stacked ? 0 : this.barDatasetIndex,     // used to calculate arc config
        bandwidth = xscale.bandwidth?.() ?? 0,
        radialOptions = config.merged('radial') || {},
        padding = radialOptions.padding ?? 0,
        interPadding = radialOptions.interPadding ?? 0;

    const findEndAngle = utils.findEndAngle(s_index, barSeriesCount, bandwidth);

    function enter(d, i) {
        let val;
        if (chart.phase == 'legendFilter') {
            return _position.startAngle.enter.apply(this, arguments) + E4;
        };

        switch (anime.type) {
            case VERTICALALL_ANIMATION:
                val = update.apply(this, arguments);
            case FAN_ANIMATION:
                val = _position.startAngle.update.apply(this, arguments) + E4
            default:
                val = update.apply(this, arguments);
        }
        return val
    }
    function update(d, i) {
        // const padding = isNumber(interPadding) ? interPadding : perToPx(interPadding, bandwidth / 2, 0)
        let val = findEndAngle(_getXYValue(d));
        // val = barSeriesCount > 1 ? findEndAngle(val, s_index) : val + bandwidth;
        return _positionComponent.endAngle.call(this, arguments[0], arguments[1], val);
    }
    function exit(d, i) {
        // return this.zc_cache.startAngle + E4;
        // const liveorder = d.liveorder || 0;
        return this.zc_cache.startAngle + E4;
    }

    return { enter, update, exit };
}

function innerRadius() {
    const self = this;
    const { chart, config, helpers, data, builderC, commonOption } = this,
        { _getXYValue, animationOptions: anime, xscale, yscale, stacked } = builderC,
        barSeriesCount = stacked ? 1 : commonOption.barSeriesCount,
        s_index = stacked ? 0 : this.barDatasetIndex,     // used to calculate arc config
        { position, positionComponent } = helpers,
        _positionComponent = positionComponent[KEY],
        radialOptions = config.merged('radial') || {},
        plotarea = chart.plotarea;

    // const findInnerRadius = utils.findInnerRadius(s_index, barSeriesCount, )

    function enter(d, i) {
        let val;
        switch (anime.type) {
            case VERTICALALL_ANIMATION:
            case FAN_ANIMATION:
                val = update.apply(this, arguments);
            default:
                val = update.apply(this, arguments);
        }
        return val;

    }
    function update(d, i) {
        const dim = Math.min(plotarea.width, plotarea.height);
        let val = perToPx(radialOptions.innerRadius, dim, 0);
        val = stacked ? _getXYValue(d, 'r(min)') : val;
        return _positionComponent.innerRadius.call(this, arguments[0], arguments[1], val);
    }
    function exit(d, i) {
        const dim = Math.min(plotarea.width, plotarea.height);
        return perToPx(radialOptions.innerRadius, dim, 0);
    }

    return { enter, update, exit };
}

function outerRadius() {
    const self = this;
    const { chart, config, helpers, data, builderC, commonOption } = this,
        { _getXYValue, animationOptions: anime, xscale, yscale, stacked } = builderC,
        barSeriesCount = stacked ? 1 : commonOption.barSeriesCount,
        s_index = stacked ? 0 : this.barDatasetIndex,     // used to calculate arc config
        { position, positionComponent } = helpers,
        _position = position[KEY],
        _positionComponent = positionComponent[KEY];

    function enter(d, i) {
        let val;
        if (chart.phase == 'legendFilter') {
            return update.apply(this, arguments) + 0.0001;
        }
        switch (anime.type) {
            case VERTICALALL_ANIMATION:
                val = _position.innerRadius.update.apply(this, arguments) + E4;
            case FAN_ANIMATION:
                val = update.apply(this, arguments) + 0.0001;
            default:
                val = _position.innerRadius.update.apply(this, arguments) + E4;
        }
        return val;
    }
    function update(d, i) {
        let val = _getXYValue(d, 'r');
        return _positionComponent.outerRadius.call(this, arguments[0], arguments[1], val);
    }
    function exit(d, i) {
        return _getXYValue(d, 'r');
    }

    return { enter, update, exit };
}

function cornerRadius() {
    const self = this;
    const { chart, config, helpers, } = this,
        { positionComponent } = helpers,
        _positionComponent = positionComponent[KEY],
        radialOptions = config.merged('radial') || {},
        cornerRadius = radialOptions.cornerRadius ?? 0;

    function enter(d, i) {
        return cornerRadius ? E4 : 0;
    }
    function update(d, i) {
        return _positionComponent.cornerRadius.call(this, arguments[0], arguments[1], cornerRadius);
    }
    function exit(d, i) {
        return cornerRadius ? E4 : 0;
    }

    return { enter, update, exit };
}

/**
 * Bar interPadding
 */
function padAngle() {
    const self = this;
    const { chart, config, helpers, } = this,
        { positionComponent } = helpers,
        _positionComponent = positionComponent[KEY],
        radialOptions = config.merged('radial') || {},
        padding = radialOptions.padding ?? 0;

    function enter(d, i) {
        return 0;
    }
    function update(d, i) {
        return _positionComponent.padAngle.call(this, arguments[0], arguments[1], padding);
    }
    function exit(d, i) {
        return 0;
    }

    return { enter, update, exit };
}

let utils = {
    findStartAngle: (index, count, bandwidth) => {
        return (val) => {
            return val + (bandwidth * index / count);
        }
    },
    findEndAngle: (index, count, bandwidth) => {
        return (val) => {
            return val + (bandwidth * (index + 1) / count);
        }
    },
    findOuterRadius: (scale, count) => {
        return (val, index) => {
            return val
        }
    },
    findInnerRadius: (scale, count) => {
        return (val, index) => {
            return val
        }
    }
}

function radialbar_encode() {
    position.call(this);
    styles.call(this);
}

ParserRegistry.encodes('radialbar', radialbar_encode);